<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Categories</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@selectedCategories.Contains(category)"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <label>
                Min:
                <input type="number" step="0.01" min="0" @bind="minPrice" placeholder="Min" />
            </label>
            <label>
                Max:
                <input type="number" step="0.01" min="0" @bind="maxPrice" placeholder="Max" />
            </label>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn btn-primary" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-secondary" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <main class="catalog-main">
        @if (isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products...</p>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="catalog-error">
                <p>Error: @errorMessage</p>
                <button class="btn btn-primary" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (result is not null && result.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found matching your criteria.</p>
            </div>
        }
        else if (result is not null)
        {
            <div class="catalog-toolbar">
                <div class="sort-control">
                    <label>Sort by:</label>
                    <select @bind="sortBy" @bind:after="LoadProducts">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="results-info">
                    Showing @(((result.Page - 1) * result.PageSize) + 1)–@(Math.Min(result.Page * result.PageSize, result.TotalCount)) of @result.TotalCount products
                </span>
            </div>

            <div class="product-grid">
                @foreach (var product in result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            <div class="pagination">
                <button class="btn btn-page" disabled="@(currentPage <= 1)" @onclick="PreviousPage">Previous</button>
                @for (int i = 1; i <= totalPages; i++)
                {
                    var pageNum = i;
                    <button class="btn btn-page @(pageNum == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }
                <button class="btn btn-page" disabled="@(currentPage >= totalPages)" @onclick="NextPage">Next</button>
            </div>
        }
    </main>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int pageSize = 12;
    private int totalPages;
    private bool isLoading = true;
    private string? errorMessage;
    private PagedResult<Product>? result;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = SearchProducts();
            categories = await categoriesTask;
            await productsTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        try
        {
            errorMessage = null;
            isLoading = true;
            await SearchProducts();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );

        result = await ProductService.SearchAsync(filter, sortBy, currentPage, pageSize);
        totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
        isLoading = false;
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task PreviousPage()
    {
        if (currentPage > 1)
        {
            currentPage--;
            await LoadProducts();
        }
    }

    private async Task NextPage()
    {
        if (currentPage < totalPages)
        {
            currentPage++;
            await LoadProducts();
        }
    }

    private void HandleProductSelected(Product product)
    {
        // Parent-level navigation hook; in a real app, navigate to /product/{product.Id}
    }

    private void HandleAddToCart(Product product)
    {
        // Add to cart logic
    }
}
"}

