toolArgs.file_text:
.catalog-container {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border-right: 1px solid #e0e0e0;
}

.catalog-sidebar h3 {
    margin-top: 0;
}

.catalog-sidebar h4 {
    margin-bottom: 0.5rem;
}

.filter-section {
    margin-bottom: 1.5rem;
}

.filter-section label {
    display: block;
    margin-bottom: 0.4rem;
}

.filter-section input[type="number"] {
    width: 100%;
    padding: 0.4rem;
    margin-top: 0.2rem;
    box-sizing: border-box;
}

.filter-checkbox {
    display: flex !important;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.catalog-main {
    width: 75%;
    flex: 1;
}

.catalog-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
    padding: 0.5rem 0;
    border-bottom: 1px solid #e0e0e0;
}

.sort-control {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.sort-control select {
    padding: 0.4rem;
}

.results-info {
    color: #666;
    font-size: 0.9rem;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.5rem;
}

.catalog-loading,
.catalog-error,
.catalog-empty {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 300px;
    color: #666;
}

.catalog-error {
    color: #c0392b;
}

.pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.4rem;
    margin-top: 2rem;
    padding: 1rem 0;
}

.btn {
    padding: 0.5rem 1rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-primary {
    background-color: #2563eb;
    color: white;
    border-color: #2563eb;
}

.btn-secondary {
    background-color: #f3f4f6;
    color: #374151;
}

.btn-page {
    min-width: 2.2rem;
    text-align: center;
}

.btn-page.active {
    background-color: #2563eb;
    color: white;
    border-color: #2563eb;
}

