toolArgs.file_text:
@using sv_d2efc209926845f294978b2d5241afea.Services

<div class="product-card" @onclick="OnCardClick">
    <div class="product-image" title="@Product.Name">
        <span>@Product.Name</span>
    </div>
    <div class="product-info">
        <h4 class="product-name">@Product.Name</h4>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <p class="product-rating">@GetStarRating(Product.Rating)</p>
        @if (!Product.InStock)
        {
            <span class="out-of-stock-badge">Out of Stock</span>
        }
        <button class="btn btn-add-to-cart"
                disabled="@(!Product.InStock)"
                @onclick="OnAddToCartClick"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }

    private async Task OnCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClick()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

